INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('30-finance-os',3,30,'FINANCE OS','He dieu hanh tai chinh',30,'draft','2026-06-20T16:33:13Z','2026-06-20T16:33:13Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('19f9d5ea-62bc-4da5-8422-bc1f4985f080','30-finance-os',NULL,2,'30.1 Finance OS Là Gì?','301-finance-os-la-gi',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9d7c84a8-4b91-4d6e-b510-9f0e0be2e36c','19f9d5ea-62bc-4da5-8422-bc1f4985f080',0,'text','**Thay Đổi Tư Duy Từ Kế Toán Ghi Chép Sang Quản Trị Dòng Tiền**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c6be4a3f-21cc-40dc-bdba-2c1721b24d50','19f9d5ea-62bc-4da5-8422-bc1f4985f080',1,'text','Nhiều chủ phòng khám nha khoa thường nhầm lẫn giữa việc làm kế toán thuế (ghi nhận số liệu quá khứ để báo cáo) với quản trị tài chính doanh nghiệp. **Finance OS** không phải là công cụ ghi sổ đơn thuần. Đây là hệ điều hành quản trị toàn diện dòng tiền, doanh thu, chi phí, biên lợi nhuận ròng và hiệu quả tài chính thời gian thực (real-time) của nha khoa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3dc717b8-88e7-4cb0-968f-47793205e8e0','19f9d5ea-62bc-4da5-8422-bc1f4985f080',2,'text','Hệ điều hành này hoạt động như một "trung tâm điều khiển" giúp Bác sĩ Vinh và ban quản trị không bao giờ rơi vào trạng thái mù mờ về tiền bạc. Finance OS sinh ra để trả lời chính xác 6 câu hỏi sống còn của một phòng khám RHM:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('38e377fb-d065-4480-bc0a-eac581d67797','19f9d5ea-62bc-4da5-8422-bc1f4985f080',3,'text','- **Doanh thu thực tế đang đến từ đâu?** Bóc tách chính xác tỷ trọng dòng tiền từ các nhóm dịch vụ: Chỉnh nha, Implant, Răng sứ thẩm mỹ hay Nha khoa tổng quát.- **Dịch vụ nào đang nuôi sống bộ máy?** Xác định chính xác biên lợi nhuận của từng dịch vụ sau khi trừ đi chi phí vật liệu (Labo, vật tư tiêu hao) và công khám của bác sĩ.- **Chi phí nào đang thầm lặng ăn mòn lợi nhuận?** Nhận diện các khoản lãng phí vô hình trong quỹ lương, chi phí quản lý vận hành sảnh hoặc khấu hao trang thiết bị.- **Ngân sách Marketing có tạo ra dòng tiền thật?** Đo lường chỉ số ROI của từng chiến dịch truyền thông trên kênh hay website , bóc tách giữa "doanh thu trên giấy" và tiền mặt thực tế thu về quỹ.- **Hiệu suất tài chính của đội ngũ đạt mức bao nhiêu?** Đánh giá năng lực tạo ra giá trị kinh tế của từng bác sĩ điều trị, trợ thủ và chuyên viên tư vấn phác đồ (TCO).- **Phòng khám có đủ động năng tài chính để mở rộng?** Dự báo chính xác dòng tiền tự do (Free Cash Flow) để đưa ra quyết định tái đầu tư nâng cấp công nghệ hoặc mở rộng cơ sở mới an toàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('38a4de93-9c54-4e60-869d-5dbffe717dca','30-finance-os',NULL,2,'30.2 Vai Trò Chiến Lược Của Finance OS Trong Hệ Sinh Thái Dental Empire','302-vai-tro-chien-luoc-cua-finance-os-trong-he-sinh-thai-dental-empire',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ae615cce-853a-4ed7-b22a-a919af025063','38a4de93-9c54-4e60-869d-5dbffe717dca',4,'text','Trong kiến trúc vận hành Dental Empire, Finance OS đóng vai trò là **lớp lưới kiểm soát an ninh tài chính**. Một phòng khám có thể có bác sĩ giỏi, marketing mạnh và sảnh đông khách, nhưng nếu lớp lưới tài chính bị rách, toàn bộ hệ thống sẽ sụp đổ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('36179c6e-0bfc-4c70-a898-73074959e7ab','38a4de93-9c54-4e60-869d-5dbffe717dca',5,'text','Hệ điều hành Finance OS được thiết kế để triệt tiêu vĩnh viễn 5 sai lầm kinh điển trên lâm sàng kinh doanh nha khoa:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7f04373d-bcf8-4d94-b12b-61182158da0d','38a4de93-9c54-4e60-869d-5dbffe717dca',6,'image',NULL,'book/30-finance-os/4147d94f-eb21-4eca-9e61-5887c7220c46-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('50d9e3b0-3c5a-42e1-bef2-948a9ba90a62','30-finance-os',NULL,2,'30.3 Biên Lợi Nhuận Gộp Dịch Vụ (GPM_{\\text{service}})','303-bien-loi-nhuan-gop-dich-vu-gpmtextservice',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9aabaf5f-15dd-49ce-9caf-daa8a6276901','50d9e3b0-3c5a-42e1-bef2-948a9ba90a62',7,'text','Để quản trị dòng tiền tận gốc, Finance OS bắt buộc kế toán và quản lý cơ sở phải tính toán biên lợi nhuận gộp cho từng nhóm dịch vụ lâm sàng theo công thức:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f388dbe9-c042-49e3-8e8b-248722d70471','50d9e3b0-3c5a-42e1-bef2-948a9ba90a62',8,'text','GPM_{\\text{service}} (\\%) = \\left( \\frac{\\text{Giá phác đồ} - (\\text{Chi phí Labo} + \\text{Chi phí vật tư tiêu hao} + \\text{Thù lao Bác sĩ})}{\\text{Giá phác đồ}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c619e52a-4338-45f8-95f5-9f1ac610ecb7','50d9e3b0-3c5a-42e1-bef2-948a9ba90a62',9,'text','**Tiêu chuẩn an toàn Dental Empire:** Chỉ số GPM_{\\text{service}} của các dịch vụ lớn (Implant, Sứ thẩm mỹ) tại nha khoa bắt buộc phải được kiểm soát ở mức **\\ge 60\\%**. Nếu chỉ số này tụt xuống dưới 45%, Finance OS sẽ lập tức yêu cầu tối ưu lại chi phí chuỗi cung ứng vật liệu hoặc điều chỉnh lại cơ cấu thưởng của nhân sự trực sàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aaccb206-cb4f-4937-8483-ab2caa41065c','50d9e3b0-3c5a-42e1-bef2-948a9ba90a62',10,'image',NULL,'book/30-finance-os/1567f30a-ec56-4f29-9600-4bc9402558a9-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('98f89193-ce23-4efb-8af6-e44b1e0b29ba','50d9e3b0-3c5a-42e1-bef2-948a9ba90a62',11,'text','**Mantra điều hành Finance OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3ac4a768-bda2-4745-82a5-8739c44f0581','50d9e3b0-3c5a-42e1-bef2-948a9ba90a62',12,'text','*"Doanh thu là phù du, dòng tiền là nhịp thở, lợi nhuận mới là sự sống. Một người làm chủ phòng khám thông minh không nhìn vào độ đông đúc của sảnh chờ để đánh giá sự thành công, họ nhìn vào độ khỏe mạnh của các con số trên bảng cân đối dòng tiền."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e5b285fa-7f9a-4fee-a5af-9fd6bf13081e','30-finance-os',NULL,2,'30.4 Bản Đồ Kiến Trúc 7 Phần Của Hệ Điều Hành Finance OS','304-ban-o-kien-truc-7-phan-cua-he-ieu-hanh-finance-os',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e1c9bcba-6157-494a-a8b2-e6b8a3d49d8a','e5b285fa-7f9a-4fee-a5af-9fd6bf13081e',13,'text','Để hạ tầng tài chính của phóng khám vận hành tự động, minh bạch và loại bỏ hoàn toàn các lỗi thất thoát dòng tiền, **Finance OS** được cấu trúc thành 7 cấu phần lõi. Tháp kiến trúc này dịch chuyển phòng khám từ trạng thái đối phó với số liệu sang trạng thái làm chủ và điều khiển dòng tiền theo thời gian thực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d3781467-6405-4933-8fd4-af8908faccf2','e5b285fa-7f9a-4fee-a5af-9fd6bf13081e',14,'image',NULL,'book/30-finance-os/8786422f-9dde-4296-a826-38f16d0a0f9a-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b6f04e3c-6d35-4ab0-a308-9207cdcee34a','30-finance-os',NULL,2,'30.5 Bóc Tách Chi Tiết Vận Hành Của 7 Cấu Phần Cốt Lõi','305-boc-tach-chi-tiet-van-hanh-cua-7-cau-phan-cot-loi',4,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('56b43621-8680-4c86-a24c-330625405bd9','30-finance-os','b6f04e3c-6d35-4ab0-a308-9207cdcee34a',3,'Revenue Tracking (Phân rã dòng doanh thu)Bản chất: Không chỉ ghi nhận một con số doanh thu tổng (Gross Billing). Hệ thống bắt buộc phải bóc tách dòng tiền theo từng tầng: Doanh thu theo loại dịch vụ (Chỉnh nha, Implant, Sứ), doanh thu theo phân khúc khách hàng (Khách mới, khách Recall, khách Referral) và trạng thái thanh toán (Trả thẳng vs Trả góp).Mục tiêu quản trị: Phát hiện nhanh đâu là dịch vụ đang gánh doanh số chính cho cơ sở Hà Nội và dự báo chính xác xu hướng tiêu dùng của thị trường.','revenue-tracking-phan-ra-dong-doanh-thuban-chat-khong-chi-ghi-nhan-mot-con-so-do',5,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f9209c57-aa3b-4cb3-8247-54a0879ad80d','30-finance-os','b6f04e3c-6d35-4ab0-a308-9207cdcee34a',3,'Cost Tracking (Kiểm soát chi phí nghiêm ngặt)Bản chất: Số hóa và phân loại toàn bộ dòng tiền chi ra (Outflow) thành các danh mục chi phí cứng để triệt tiêu các "lỗ rò rỉ" tài chính vô hình.','cost-tracking-kiem-soat-chi-phi-nghiem-ngatban-chat-so-hoa-va-phan-loai-toan-bo-',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bcc2f4c8-78e4-425a-a0aa-52f1b3977b4b','f9209c57-aa3b-4cb3-8247-54a0879ad80d',15,'text','- **Danh mục kiểm soát:***Chi phí trực tiếp (COGS):* Phí Labo (mão sứ, khay niềng), vật tư tiêu hao (thuốc tê, implant, tay khoan).- *Chi phí nhân sự:* Quỹ lương cứng, lương hiệu suất của Bác sĩ Vinh, đội ngũ phụ tá và bộ phận sảnh.- *Chi phí cố định:* Tiền thuê mặt bằng, điện nước, khấu hao trang thiết bị máy móc.- *Chi phí tăng trưởng:* Ngân sách đổ vào hệ thống Marketing và truyền thông.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('58ff4619-dec0-4264-813a-4ee10a8ad813','30-finance-os','b6f04e3c-6d35-4ab0-a308-9207cdcee34a',3,'Profit Tracking (Đo lường chỉ số lợi nhuận)Bản chất: Tách bạch rõ ràng giữa lợi nhuận gộp (Gross Profit) và lợi nhuận ròng (Net Profit) của toàn phòng khám hằng tháng dựa trên phương trình toán học:\\text{Net Profit} = \\text{Revenue} - \\text{Total Cost}Mục tiêu quản trị: Đảm bảo phòng khám không rơi vào cái bẫy "doanh thu ảo - lỗ thật". Nếu doanh thu tăng trưởng nhưng đồ thị lợi nhuận đi ngang, quản lý cơ sở phải lập tức kích hoạt quy trình kiểm toán chi phí vận hành.','profit-tracking-o-luong-chi-so-loi-nhuanban-chat-tach-bach-ro-rang-giua-loi-nhua',7,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4f2b3d2f-0ae1-4137-bbbc-9c4fcdbcb997','30-finance-os','b6f04e3c-6d35-4ab0-a308-9207cdcee34a',3,'Cash Flow Management (Điều khiển mạch máu dòng tiền)Bản chất: Quản trị sự sống còn của phòng khám thông qua việc kiểm soát độ lệch pha giữa dòng tiền mặt thực tế thu về (Cash Inflow) và tiền thực tế chi ra (Cash Outflow).Trọng tâm đối với Nha khoa: Kiểm soát chặt chẽ Hạn mức công nợ trả góp (đặc biệt là tệp khách niềng răng). Hệ thống CRM phải tự động tính toán tỷ lệ nợ xấu và lên lịch nhắc thu tiền đồng bộ với tiến độ dịch chuyển răng trên lâm sàng.','cash-flow-management-ieu-khien-mach-mau-dong-tienban-chat-quan-tri-su-song-con-c',8,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('77338eff-1015-4ae2-b10d-8ba78d70199b','30-finance-os','b6f04e3c-6d35-4ab0-a308-9207cdcee34a',3,'Treatment Profitability (Đo lường hiệu suất sinh lời ca điều trị)Bản chất: Áp dụng tư duy kinh tế đơn vị (Unit Economics) vào từng đầu ghế nha. Tính toán chính xác số tiền lãi thực tế thu về sau khi một bệnh nhân hoàn tất một phác đồ cụ thể.Mục tiêu quản trị: Giúp chủ phòng khám biết rõ dịch vụ nào có biên lợi nhuận cao để tập trung đẩy mạnh, và dịch vụ nào biên lợi nhuận quá thấp (do chi phí vật liệu hoặc thù lao bác sĩ quá cao) để điều chỉnh lại bảng giá thị trường.','treatment-profitability-o-luong-hieu-suat-sinh-loi-ca-ieu-triban-chat-ap-dung-tu',9,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('51bfcd55-3f45-4dad-87c6-32eea7e88a38','30-finance-os','b6f04e3c-6d35-4ab0-a308-9207cdcee34a',3,'Marketing ROI (Kiểm toán hiệu quả ngân sách tăng trưởng)Bản chất: Đo lường sòng phẳng mối quan hệ giữa chi phí marketing bỏ ra và dòng doanh thu thực thu mang về cho hệ thống.Chỉ số kiểm soát: Tính toán chi phí thu hút một khách hàng đến sàn thực tế (CAC) và giá trị vòng đời của khách hàng đó (LTV). Finance OS sẽ khóa các chiến dịch chạy Ads đốt tiền nếu chỉ số LTV / CAC &lt; 3. Đồng thời, hệ thống ghi nhận chính xác hiệu quả kinh tế của các nội dung hữu cơ từ kênh TikTok @thichlamrang và nguồn khách giới thiệu từ Referral OS.','marketing-roi-kiem-toan-hieu-qua-ngan-sach-tang-truongban-chat-o-luong-song-phan',10,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3d968559-d314-4e3b-93c9-fed7ade89471','30-finance-os','b6f04e3c-6d35-4ab0-a308-9207cdcee34a',3,'Financial Dashboard (Bảng điều khiển tài chính tối cao)Bản chất: Lớp hiển thị trực quan hóa toàn bộ dữ liệu của 6 phần trên lên một màn hình điều hành thời gian thực.Mục tiêu quản trị: Thay thế hoàn toàn các báo cáo bằng file Excel thủ công, chậm trễ. Giúp Founder (Bác sĩ Vinh) chỉ cần nhìn vào Dashboard là nắm bắt được ngay số dư quỹ an toàn, dòng tiền dự kiến trong 30 ngày tới để đưa ra các quyết định tái đầu tư nâng cấp cơ sở hạ tầng một cách khoa học.','financial-dashboard-bang-ieu-khien-tai-chinh-toi-caoban-chat-lop-hien-thi-truc-q',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b42914da-36fa-422d-82cf-73ba19c51fb7','3d968559-d314-4e3b-93c9-fed7ade89471',16,'text','**Mantra điều hành cấu trúc Finance OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dc36e646-25d8-4de5-97d1-81775eddfc56','3d968559-d314-4e3b-93c9-fed7ade89471',17,'text','*"Hạ tầng 7 phần của Finance OS vận hành như một hệ thống tuần hoàn khép kín. Một phòng khám không phân rã rõ ràng 7 cấu phần này sẽ giống như một bác sĩ điều trị bệnh mà không có phim chụp X-quang — hoàn toàn đoán mò và đẩy doanh nghiệp vào rủi ro mất thanh khoản. Hãy số hóa toàn bộ tháp kiến trúc này để làm chủ dòng tiền của bạn."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('05e66bab-273d-468a-9a0f-7be020a2760d','30-finance-os','3d968559-d314-4e3b-93c9-fed7ade89471',4,'PHẦN 1: REVENUE TRACKING - QUY TRÌNH SỐ HÓA VÀ PHÂN RÃ DÒNG DOANH THU','phan-1-revenue-tracking-quy-trinh-so-hoa-va-phan-ra-dong-doanh-thu',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb0efa56-761f-4335-ad69-52bdc7113cbe','05e66bab-273d-468a-9a0f-7be020a2760d',18,'text','Nhìn vào một con số doanh thu tổng (Gross Revenue) cuối tháng để đánh giá sự phát triển của nha khoa là một tư duy tài chính mơ hồ. Doanh thu tổng rất dễ che giấu các lỗ hổng vận hành lâm sàng và sự lãng phí ngân sách tiếp thị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d639c040-c416-4a95-8a2d-9526cddd7969','05e66bab-273d-468a-9a0f-7be020a2760d',19,'text','Để kiểm soát dòng tiền một cách khoa học, **Finance OS** bắt buộc bộ phận kế toán và hệ thống CRM phải thực hiện phân rã doanh thu thực thu theo hai trục tọa độ cứng: **Phân rã theo danh mục dịch vụ** (Biết tiền đến từ thủ thuật nào) và **Phân loại theo nguồn khách** (Biết tiền đến từ kênh truyền thông nào).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f2ca75b0-5256-4739-aba7-e3ed007d9a34','30-finance-os','05e66bab-273d-468a-9a0f-7be020a2760d',5,'Ma Trận Phân Rã Doanh Thu Theo Danh Mục Lâm Sàng','ma-tran-phan-ra-doanh-thu-theo-danh-muc-lam-sang',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1cb8b13c-42be-459e-8a94-79242869266b','f2ca75b0-5256-4739-aba7-e3ed007d9a34',20,'text','Việc chia nhỏ dòng tiền đầu vào theo từng nhóm dịch vụ giúp ban quản trị nhận diện chính xác đâu là "động cơ kinh tế chính" nuôi sống bộ máy và đâu là dịch vụ phễu cần tối ưu hóa hiệu suất sử dụng ghế nha:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5589e84c-908c-4f36-9006-0ad0b0bd4fa5','f2ca75b0-5256-4739-aba7-e3ed007d9a34',21,'image',NULL,'book/30-finance-os/34018575-b1dc-4857-8d77-71519449d3f3-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('72578f1d-d9a8-4a83-8433-add1c985fc20','30-finance-os','05e66bab-273d-468a-9a0f-7be020a2760d',5,'Chỉ số cơ cấu doanh thu theo dịch vụ','chi-so-co-cau-doanh-thu-theo-dich-vu',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5c293b35-6a7a-4050-8cf3-94ed4bd42b5c','72578f1d-d9a8-4a83-8433-add1c985fc20',22,'image',NULL,'book/30-finance-os/3870df49-dda8-49fc-b297-4863b9f93ef3-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('64775201-f95a-4b7a-b524-673f181cad79','30-finance-os','05e66bab-273d-468a-9a0f-7be020a2760d',5,'Hệ Thống Định Danh Doanh Thu Theo Nguồn Khách (Attribution Matrix)','he-thong-inh-danh-doanh-thu-theo-nguon-khach-attribution-matrix',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ab929c7a-02c8-41cc-99c6-a5c64e1914c3','64775201-f95a-4b7a-b524-673f181cad79',23,'text','Nếu không phân loại nguồn khách hàng gắn liền với từng hóa đơn thanh toán, phòng khám sẽ rơi vào cái bẫy "phân bổ ngân sách mù". Bạn có thể đang đổ hàng trăm triệu vào các chiến dịch quảng cáo trả phí (Paid Ads) kém hiệu quả, trong khi dòng tiền thực tế lại đang được mang về từ các video ngắn hữu cơ hoặc lời bảo chứng từ tệp khách cũ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c927563a-0d84-4609-80c2-574e3d1f21e9','64775201-f95a-4b7a-b524-673f181cad79',24,'text','Hệ thống CRM bắt buộc phải tự động khóa mã nguồn khách vào payload doanh thu theo ma trận đối soát dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2919b64c-ebfc-4fd6-8e7c-1771e0732030','64775201-f95a-4b7a-b524-673f181cad79',25,'text','**Mantra điều hành Revenue Tracking:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5300956e-0360-48af-9ea7-3b6898577723','64775201-f95a-4b7a-b524-673f181cad79',26,'text','*"Đừng bao giờ chấp nhận một báo cáo doanh thu chung chung. Tài chính sạch là tài chính phải nhìn rõ nguồn gốc của từng đồng tiền mặt bước vào két sắt. Biết rõ dịch vụ nào tạo tiền và kênh truyền thông nào sinh lời chính là vũ khí giúp phòng khám tối ưu hóa biên lợi nhuận ròng một cách bền vững."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d3500bf4-af00-4a8d-ad84-c696ba61ae41','30-finance-os','3d968559-d314-4e3b-93c9-fed7ade89471',4,'PHẦN 2: COST TRACKING - THEO DÕI VÀ KIỂM SOÁT CHI PHÍ ĐẦU GHẾ NHA','phan-2-cost-tracking-theo-doi-va-kiem-soat-chi-phi-au-ghe-nha',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b1d1f0a4-5d60-40f9-86b8-a5f120c5313a','d3500bf4-af00-4a8d-ad84-c696ba61ae41',27,'text','Nếu xem doanh thu là dòng máu nạp vào thì chi phí chính là áp lực van xả của hệ thống nha khoa. Nhiều phòng khám RHM gặp hiện tượng sập nguồn thanh khoản chỉ vì người điều hành không phân định rõ ràng giữa Định phí (chi phí cố định) và Biến phí (chi phí biến đổi). Việc cào bằng mọi khoản chi ra khiến phòng khám không thể tính toán được điểm hòa vốn thực tế và biên lợi nhuận gộp của từng ca lâm sàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4922ea55-8f61-45cf-bfaf-c1ac61806453','d3500bf4-af00-4a8d-ad84-c696ba61ae41',28,'text','Hệ thống Finance OS phân rã toàn bộ chi phí chi ra (Outflow) thành hai danh mục xương sống để phục vụ cho hoạt động kiểm toán hằng tuần.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('288b0809-ab28-466d-92e3-d44b027b9026','30-finance-os','d3500bf4-af00-4a8d-ad84-c696ba61ae41',5,'Nhóm Chi Phí Cố Định (Fixed Costs) - Định Phí Vận Hành','nhom-chi-phi-co-inh-fixed-costs-inh-phi-van-hanh',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('79d1016a-56cd-4bb7-bcf8-648c1b69da62','288b0809-ab28-466d-92e3-d44b027b9026',29,'text','Chi phí cố định là những khoản chi bắt buộc phòng khám phải chi trả hằng tháng để duy trì sự tồn tại của cơ sở, bất kể tháng đó phòng khám có 1.000 bệnh nhân hay không có một ai bước vào sảnh. Việc kiểm soát định phí giúp anh xác định được "ngưỡng thở" tối thiểu của doanh nghiệp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b73145b1-3b10-4443-97f6-e24bc597e0fc','30-finance-os','d3500bf4-af00-4a8d-ad84-c696ba61ae41',5,'Nhóm Chi Phí Biến Đổi (Variable Costs) - Biến Phí Lâm Sàng','nhom-chi-phi-bien-oi-variable-costs-bien-phi-lam-sang',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a390c0a6-d49e-4f59-8e36-899e790da807','b73145b1-3b10-4443-97f6-e24bc597e0fc',30,'text','Chi phí biến đổi là những khoản chi chỉ phát sinh tỷ lệ thuận với số lượng bệnh nhân và khối lượng thủ thuật lâm sàng thực tế diễn ra tại phòng khám. Biến phí chính là nguyên liệu cấu thành nên Giá vốn hàng bán (COGS) trên từng răng sứ hay từng ca cấy ghép Implant.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cf984dc5-3a50-4432-bcec-482bbf0482e4','b73145b1-3b10-4443-97f6-e24bc597e0fc',31,'text','- **Công thức và chỉ số Kiểm soát Biến phí Vật liệu (****COGS_{\\text{clinical}}****)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('13044a58-425d-4c85-b1ce-6a5b9c682ef4','b73145b1-3b10-4443-97f6-e24bc597e0fc',32,'image',NULL,'book/30-finance-os/e6c3e8f2-0d55-4663-9380-7b8980c2a89f-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3f25c690-1435-48d4-aed3-5c3d6222b001','b73145b1-3b10-4443-97f6-e24bc597e0fc',33,'text','**Mantra điều hành Cost Tracking:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e261ce7f-6c14-4612-b2b8-8352cc6e5c8e','b73145b1-3b10-4443-97f6-e24bc597e0fc',34,'text','*"Định phí quyết định việc phòng khám có thể sống sót qua mùa dịch hay mùa thấp điểm hay không. Biến phí quyết định việc phòng khám có kiếm được nhiều tiền khi đông khách hay không. Hãy số hóa và kiểm soát từng mũi khoan, từng hóa đơn điện để bịt kín mọi lỗ rò rỉ dòng tiền trước khi nghĩ đến chuyện mở rộng quy mô."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('eb2b49c7-4b1c-4760-8190-7262d0302475','30-finance-os','3d968559-d314-4e3b-93c9-fed7ade89471',4,'PHẦN 2: COST TRACKING - THEO DÕI VÀ KIỂM SOÁT CHI PHÍ ĐẦU GHẾ NHA','phan-2-cost-tracking-theo-doi-va-kiem-soat-chi-phi-au-ghe-nha',19,'[]');
