INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('540a7031-7037-49b9-9fe2-13a492adaa3e','3891a98e-dc53-4585-a4ba-7b5aeac20e98',38,'text','Chi phí biến đổi là những khoản chi chỉ phát sinh tỷ lệ thuận với số lượng bệnh nhân và khối lượng thủ thuật lâm sàng thực tế diễn ra tại phòng khám. Biến phí chính là nguyên liệu cấu thành nên Giá vốn hàng bán (COGS) trên từng răng sứ hay từng ca cấy ghép Implant.',NULL,NULL,NULL,NULL,NULL);
