INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2ac17c4d-bf47-4157-9ca0-134909c7fe44','3891a98e-dc53-4585-a4ba-7b5aeac20e98',41,'text','**Mantra điều hành Cost Tracking:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('177a1837-018a-4acd-9184-ef9b7baefe89','3891a98e-dc53-4585-a4ba-7b5aeac20e98',42,'text','*"Định phí quyết định việc phòng khám có thể sống sót qua mùa dịch hay mùa thấp điểm hay không. Biến phí quyết định việc phòng khám có kiếm được nhiều tiền khi đông khách hay không. Hãy số hóa và kiểm soát từng mũi khoan, từng hóa đơn điện để bịt kín mọi lỗ rò rỉ dòng tiền trước khi nghĩ đến chuyện mở rộng quy mô."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9d900828-2652-437e-8805-80ebced545c5','30-finance-os','3d968559-d314-4e3b-93c9-fed7ade89471',4,'PHẦN 4: CASH FLOW MANAGEMENT - QUẢN TRỊ VÀ ĐIỀU KHIỂN MẠCH MÁU DÒNG TIỀN','phan-4-cash-flow-management-quan-tri-va-ieu-khien-mach-mau-dong-tien',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('46f79344-5e6d-4d44-bf23-aa405622f1b1','9d900828-2652-437e-8805-80ebced545c5',43,'text','Doanh thu là ảo, lợi nhuận là lý thuyết, chỉ có tiền mặt mới là thực tế. Một phòng khám nha khoa có thể phá sản ngay trên đỉnh cao doanh số nếu dòng tiền mặt bị tắc nghẽn. Cái bẫy lớn nhất của các phòng khám RHM có tệp khách chỉnh nha và Implant lớn là sự lệch pha nghiêm trọng giữa thời điểm ghi nhận doanh thu trên hợp đồng và thời điểm tiền mặt thực tế chảy vào két sắt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a789bd65-cb16-4756-9330-e31bc2427332','9d900828-2652-437e-8805-80ebced545c5',44,'text','Hệ thống **Cash Flow Management** thuộc *Finance OS* được thiết kế để làm nhiệm vụ tối cao: Đảm bảo phòng khám luôn ở trạng thái thặng dư thanh khoản, kiểm soát chặt chẽ công nợ và triệt tiêu nguy cơ mất kiểm soát tài chính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0831b99e-41a7-4707-bd71-7e9164be3e41','30-finance-os','9d900828-2652-437e-8805-80ebced545c5',5,'Phân Rã Sáu Dòng Tiền Lõi Cần Giám Sát Trên CRM','phan-ra-sau-dong-tien-loi-can-giam-sat-tren-crm',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4f3d3e5f-f03c-4ab4-940b-4a10da20a4fe','0831b99e-41a7-4707-bd71-7e9164be3e41',45,'text','Để mạch máu tài chính luôn lưu thông, bộ phận kế toán và hệ thống CRM của nha khoa **Thích Làm Răng** bắt buộc phải bóc tách dữ liệu dòng tiền thành 6 trường thông tin cứng hằng ngày:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3f41cc83-86b6-442f-8e78-2481d3a95573','0831b99e-41a7-4707-bd71-7e9164be3e41',46,'image',NULL,'book/30-finance-os/ba6e5593-d206-44aa-b991-228709ee5e85-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8482f1fe-dc89-4675-8c46-1010fd0c164f','30-finance-os','9d900828-2652-437e-8805-80ebced545c5',5,'Nguyên Tắc Kiểm Toán Dòng Tiền Theo Tuần (Weekly Cash Audit)','nguyen-tac-kiem-toan-dong-tien-theo-tuan-weekly-cash-audit',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f9d9cb62-1231-49e1-81f2-2364f6353894','8482f1fe-dc89-4675-8c46-1010fd0c164f',47,'text','Dòng tiền vận hành giống như nhịp thở, nếu bạn đợi đến cuối tháng mới lập báo cáo đối soát thì phòng khám đã có thể rơi vào trạng thái ngừng thở tài chính từ tuần thứ hai. *Finance OS* thiết lập kỷ luật bắt buộc: **Kiểm toán dòng tiền theo chu kỳ tuần (Thứ Sáu hằng tuần).**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('49818c55-c33f-4d23-8924-3b5a30010c8f','8482f1fe-dc89-4675-8c46-1010fd0c164f',48,'text','Vào ngày cuối tuần, Quản lý cơ sở và bộ phận kế toán phải trả lời sòng phẳng bộ 7 câu hỏi chất vấn hệ thống dưới đây trước khi trình báo cáo lên Sáng lập:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b821304f-611f-4fcf-9467-70c9b3ba0c93','8482f1fe-dc89-4675-8c46-1010fd0c164f',49,'text','- **Chất vấn 1:** Tuần này tổng dòng tiền mặt thực tế thu về quỹ là bao nhiêu?- **Chất vấn 2:** Tuần này tổng dòng tiền mặt thực tế đã chi ra khỏi quỹ là bao nhiêu?- **Chất vấn 3:** Số dư tiền mặt khả dụng (Cash Balance) tại két và các tài khoản ngân hàng hiện còn chính xác bao nhiêu?- **Chất vấn 4:** Tổng giá trị công nợ đến hạn phải thu từ bệnh nhân chỉnh nha/Implant tuần này là bao nhiêu, tỷ lệ thu hồi đạt mấy phần trăm?- **Chất vấn 5:** Có bao nhiêu khoản công nợ phải trả cho Labo và nhà cung cấp vật tư cần phải giải ngân trong tuần tới?- **Chất vấn 6:** Số dư tiền mặt hiện tại có đủ năng lực bao phủ an toàn cho quỹ lương, chi phí mặt bằng, hóa đơn Labo và ngân sách Marketing của tuần kế tiếp không?- **Chất vấn 7:** Phòng khám có đang gặp hiện tượng "bẫy thanh khoản" — doanh thu trên sổ sách rất cao nhưng quỹ tiền mặt lại trống rỗng hay không?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f8207583-d036-4248-9520-339e57984426','30-finance-os','9d900828-2652-437e-8805-80ebced545c5',5,'Chỉ Số Số Tháng Dự Phòng An Toàn Truyền Thống (\\text{Runway})','chi-so-so-thang-du-phong-an-toan-truyen-thong-textrunway',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cf16c943-164c-4d70-b9d8-59070d2f33d0','f8207583-d036-4248-9520-339e57984426',50,'image',NULL,'book/30-finance-os/540b443b-581f-41c3-a324-2d1d62df3afb-img09.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('629beb4b-6b85-42ee-9e15-67c5a9eaa771','f8207583-d036-4248-9520-339e57984426',51,'text','**Mantra điều hành Cash Flow Management:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4019dec9-a355-433e-8be8-76b5f70bac80','f8207583-d036-4248-9520-339e57984426',52,'text','*"Doanh số là lời hứa, tiền mặt là năng lượng. Một phòng khám vận hành không có kỷ luật kiểm toán dòng tiền tuần giống như một phi công lái máy bay xuyên qua bão mà không nhìn đồng hồ nhiên liệu. Hãy quản trị dòng tiền chặt chẽ đến từng đồng để đảm bảo sự sống còn cho doanh nghiệp của bạn."*',NULL,NULL,NULL,NULL,NULL);
