INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('54ccb282-29b7-4e07-b4fb-ad832acccc4b','5796a748-818c-4e13-9a43-4cb799bae35c',62,'text','*"Doanh số là lời hứa, tiền mặt là năng lượng. Một phòng khám vận hành không có kỷ luật kiểm toán dòng tiền tuần giống như một phi công lái máy bay xuyên qua bão mà không nhìn đồng hồ nhiên liệu. Hãy quản trị dòng tiền chặt chẽ đến từng đồng để đảm bảo sự sống còn cho doanh nghiệp của bạn."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('79ce15ce-a305-4ec9-a997-8aa4abb57cac','30-finance-os','3d968559-d314-4e3b-93c9-fed7ade89471',4,'PHẦN 6: MARKETING ROI - KIỂM TOÁN SÒNG PHẲNG NGÂN SÁCH TĂNG TRƯỞNG','phan-6-marketing-roi-kiem-toan-song-phang-ngan-sach-tang-truong',30,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6f69c1c2-4fed-43cb-b166-4511436a0b75','30-finance-os','79ce15ce-a305-4ec9-a997-8aa4abb57cac',5,'Triệt Tiêu Định Kiến: Truyền Thông Không Phải Là Điểm Số Danh Hão','triet-tieu-inh-kien-truyen-thong-khong-phai-la-iem-so-danh-hao',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4d57f7ff-eef2-471d-a295-7c90f4ac8d86','6f69c1c2-4fed-43cb-b166-4511436a0b75',63,'text','Sai lầm lớn nhất của các phòng khám nha khoa khi làm tiếp thị là bị che mắt bởi các chỉ số bề nổi (Vanity Metrics) như lượt xem video trên TikTok, lượt tương tác bài viết hay số lượng tin nhắn rác đổ về hệ thống. Trong hệ điều hành **Finance OS**, bộ phận tài chính không quan tâm kênh TikTok đạt bao nhiêu triệu view hay website  có bao nhiêu lượt truy cập nếu những con số đó không thể chuyển hóa thành dòng tiền mặt thực tế chảy vào két sắt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6f04e474-7d35-45c2-b60a-e0afcd54955e','6f69c1c2-4fed-43cb-b166-4511436a0b75',64,'text','Tiếp thị (Marketing) về bản chất tài chính là một khoản đầu tư ngắn hạn và trung hạn để mua sắm tệp khách hàng. Đã là đầu tư thì bắt buộc phải đo lường được hiệu suất sinh lời một cách sòng phẳng. Hệ thống *Finance OS* thiết lập một đường ống kết nối trực diện dữ liệu từ các chiến dịch truyền thông sang hệ thống kế toán doanh thu, đảm bảo mỗi đồng chi ra cho quảng cáo đều phải được định danh và truy vết chu kỳ hoàn vốn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7653a521-d57a-49ee-919e-79c39aa63748','30-finance-os','79ce15ce-a305-4ec9-a997-8aa4abb57cac',5,'Đường Ống Chuyển Hóa Chi Phí Thành Doanh Thu (Marketing Funnel)','uong-ong-chuyen-hoa-chi-phi-thanh-doanh-thu-marketing-funnel',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b38166ba-8bf0-46a2-8d32-cf2960c6a8d2','7653a521-d57a-49ee-919e-79c39aa63748',65,'image',NULL,'book/30-finance-os/820a3c56-b035-472c-b430-71e82b1a9107-img12.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bee3ecdf-4873-407c-9b29-4f0e7e1a06c7','7653a521-d57a-49ee-919e-79c39aa63748',66,'text','Dòng tiền tiếp thị vận hành theo một tuyến tính nghiêm ngặt. Sự đứt gãy ở bất kỳ chặng nào cũng đều dẫn đến tình trạng lãng phí tài nguyên của phòng khám:',NULL,NULL,NULL,NULL,NULL);
