INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dda12e99-ed0e-478d-90d9-d01fc5dd7d90','7653a521-d57a-49ee-919e-79c39aa63748',76,'text','Bước nhảy quyết định: Bệnh nhân ký duyệt phác đồ lâm sàng của Bác sĩ Vinh, thực hiện quẹt thẻ/thanh toán tiền mặt để chính thức can thiệp thủ thuật.',NULL,NULL,NULL,NULL,NULL);
