INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('89212fce-eae2-4a7d-ac89-5b336e002289','066ad335-0084-4c49-8b7c-7604930060c7',80,'text','**Mantra điều hành Marketing ROI:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a7434dc1-1c3b-46c7-9e37-9b0130ba0fe5','066ad335-0084-4c49-8b7c-7604930060c7',81,'text','*"Một giám đốc tiếp thị giỏi không báo cáo bằng lượt tương tác; họ báo cáo bằng số lượng phác đồ lâm sàng được ký duyệt và dòng tiền mặt thực tế nạp về tài khoản. Hãy số hóa và kiểm toán sòng phẳng từng đồng chi phí quảng cáo để đảm bảo phòng khám luôn tăng trưởng bằng nội lực thực chứng chứ không phải bằng các ảo ảnh truyền thông."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('753262d7-0d52-4125-863f-36b7a0f04d3c','30-finance-os','3d968559-d314-4e3b-93c9-fed7ade89471',4,'PHẦN 6: MARKETING ROI - KIỂM TOÁN SÒNG PHẲNG NGÂN SÁCH TĂNG TRƯỞNG','phan-6-marketing-roi-kiem-toan-song-phang-ngan-sach-tang-truong',35,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4693065b-71b1-40c6-abea-82b661379139','30-finance-os','753262d7-0d52-4125-863f-36b7a0f04d3c',5,'Triệt Tiêu Định Kiến: Truyền Thông Không Phải Là Điểm Số Danh Hão','triet-tieu-inh-kien-truyen-thong-khong-phai-la-iem-so-danh-hao',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f8a0fab3-6393-45f3-9eb1-4b6f1b49fc98','4693065b-71b1-40c6-abea-82b661379139',82,'text','Sai lầm lớn nhất của các phòng khám nha khoa khi làm tiếp thị là bị che mắt bởi các chỉ số bề nổi (Vanity Metrics) như lượt xem video trên TikTok, lượt tương tác bài viết hay số lượng tin nhắn rác đổ về hệ thống. Trong hệ điều hành **Finance OS**, bộ phận tài chính không quan tâm kênh TikTok đạt bao nhiêu triệu view hay website  có bao nhiêu lượt truy cập nếu những con số đó không thể chuyển hóa thành dòng tiền mặt thực tế chảy vào két sắt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eeef5f7f-7bcd-4da0-b773-62a92e3468bc','4693065b-71b1-40c6-abea-82b661379139',83,'text','Tiếp thị (Marketing) về bản chất tài chính là một khoản đầu tư ngắn hạn và trung hạn để mua sắm tệp khách hàng. Đã là đầu tư thì bắt buộc phải đo lường được hiệu suất sinh lời một cách sòng phẳng. Hệ thống *Finance OS* thiết lập một đường ống kết nối trực diện dữ liệu từ các chiến dịch truyền thông sang hệ thống kế toán doanh thu, đảm bảo mỗi đồng chi ra cho quảng cáo đều phải được định danh và truy vết chu kỳ hoàn vốn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('939f2d81-d589-4701-ad19-1ae926f10e51','30-finance-os','753262d7-0d52-4125-863f-36b7a0f04d3c',5,'Đường Ống Chuyển Hóa Chi Phí Thành Doanh Thu (Marketing Funnel)','uong-ong-chuyen-hoa-chi-phi-thanh-doanh-thu-marketing-funnel',37,'[]');
