INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5179dc2d-5699-4b6a-ab6b-990e6ed90e49','30-finance-os',NULL,2,'30.7 Khung Chỉ Số KPI Điều Hành Finance OS (KPI Framework)','307-khung-chi-so-kpi-ieu-hanh-finance-os-kpi-framework',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0827c1d6-304d-4389-b364-192c26956b0b','5179dc2d-5699-4b6a-ab6b-990e6ed90e49',102,'text','Một bảng số liệu tài chính mập mờ sẽ dẫn đến những quyết định điều hành sai lệch. Để biến dữ liệu tài chính từ trạng thái "ghi nhận bị động" thành vũ khí điều khiển tốc độ tăng trưởng của nha khoa. Ban quản trị bắt buộc phải chuẩn hóa bộ Khung chỉ số KPI điều hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('26d5f0c0-0a3b-45ef-8d9c-b77b5feb4515','5179dc2d-5699-4b6a-ab6b-990e6ed90e49',103,'text','Khung KPI này phân định rõ ràng: Chỉ số nào cần nhìn theo ngày để kiểm soát thực thi, chỉ số nào cần nhìn theo tuần để vá lỗ hổng vận hành chặng ngắn, và chỉ số nào cần tổng kết theo tháng để hoạch định chiến lược vĩ mô.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ed0962d6-df0f-4817-9912-91957ca9aac1','30-finance-os','5179dc2d-5699-4b6a-ab6b-990e6ed90e49',3,'Bảng Ma Trận Chỉ Số KPI Quản Trị Tài Chính Toàn Diện','bang-ma-tran-chi-so-kpi-quan-tri-tai-chinh-toan-dien',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('76ca4523-f232-4d93-acf2-6bebca558d8b','ed0962d6-df0f-4817-9912-91957ca9aac1',104,'text','Dưới đây là cấu trúc phân quyền, tần suất kiểm toán và vai trò chịu trách nhiệm đối với từng chỉ số lõi trong hệ thống Finance OS:',NULL,NULL,NULL,NULL,NULL);
