INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('231de484-6a61-4a60-ab1b-d2c2efe83db3','ee094ec3-bc99-4b17-98af-37464bdef80c',107,'text','**Mantra điều hành Khung KPI Finance OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c2eb41fa-2594-40ed-b3d9-60448b10c4a0','ee094ec3-bc99-4b17-98af-37464bdef80c',108,'text','*"Đo lường sai chỉ số tài chính giống như việc bác sĩ đọc sai phim chụp X-quang, sẽ đưa ra phác đồ điều trị sai lầm phá hủy toàn bộ doanh nghiệp. Hãy bám sát ma trận chỉ số này với kỷ luật thép để đảm bảo từng đồng vốn bỏ ra đều sinh lời và bảo vệ sự trường tồn của nha khoa Thích Làm Răng."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9a699c56-e169-49fe-98bb-ee09eb5d5d74','30-finance-os',NULL,2,'30.8 Checklist triển khai Finance OS','308-checklist-trien-khai-finance-os',44,'[]');
