INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('db653f1a-2279-4bfe-82b3-f4734e40749f','30-finance-os',NULL,2,'30.9 Tổng kế cho Finance OS','309-tong-ke-cho-finance-os',45,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('24e89b5f-4c4d-4a1d-8670-348063a0f8a3','db653f1a-2279-4bfe-82b3-f4734e40749f',110,'text','Khép lại phân hệ **Finance OS**, hệ thống quản trị tài chính tại phòng khám đã được số hóa trọn vẹn từ một bộ máy kế toán ghi chép thủ công, chậm trễ thành một hệ điều hành cốt lõi, vận hành dựa trên số liệu thực chứng thời gian thực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aa44a7d5-ca23-47a7-8d00-2710194906df','db653f1a-2279-4bfe-82b3-f4734e40749f',111,'text','Trong kiến trúc tổng thể của mô hình Dental Empire, nếu các phân hệ khác chịu trách nhiệm tạo ra lực đẩy (kéo khách, chốt phác đồ, điều trị lâm sàng), thì Finance OS chính là **hệ thống phanh và bộ giáp bảo vệ** đảm bảo phòng khám không bao giờ bị lật xe trên đường đua tăng trưởng quy mô.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1cb253f4-38e6-4b59-a7f6-51ae39c4e30d','30-finance-os','db653f1a-2279-4bfe-82b3-f4734e40749f',3,'Ba Chốt Chặn Tài Chính Tối Cao Để Duy Trì Sự Sống Còn','ba-chot-chan-tai-chinh-toi-cao-e-duy-tri-su-song-con',46,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ece097d2-2431-42fc-b928-74acdacf66e9','1cb253f4-38e6-4b59-a7f6-51ae39c4e30d',112,'text','Để kiểm soát tuyệt đối dòng tiền và loại bỏ hoàn toàn các rủi ro cảm tính, Ban điều hành và Bác sĩ Vinh bắt buộc phải giám sát bộ ba mỏ neo toán học cốt lõi này hằng tuần và hằng tháng trên CRM:',NULL,NULL,NULL,NULL,NULL);
