INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2e4283ad-8d25-4e6c-aa60-e72483d3974c','1cb253f4-38e6-4b59-a7f6-51ae39c4e30d',114,'text','- \\text{Runway} \\ge 3 \\text{ tháng định phí vận hành}
- Phòng khám có thể chịu đựng mọi biến động đột xuất của thị trường mà không bị đứt gãy mạch máu thanh khoản.',NULL,NULL,NULL,NULL,NULL);
