INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bb655f82-3f2d-4f21-8c45-b55b0c8849a4','1cb253f4-38e6-4b59-a7f6-51ae39c4e30d',116,'text','- \\text{Biên lợi nhuận gộp từng ca } (GPM_{\\text{service}}) \\ge 60\\%
