INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bf9e3707-6f78-4043-ab17-6d8d46c1ccae','0414bd4b-32fc-48ba-9675-3f89463cde97',123,'text','*"Doanh thu lớn chỉ chứng minh bạn có thị trường; lợi nhuận ròng khỏe mạnh mới chứng minh bạn có một doanh nghiệp bền vững. Hãy điều hành nha khoa bằng cái đầu lạnh của những con số thực chứng tài chính, để bảo vệ sự tử tế trong y khoa luôn được thực thi trên một nền móng vững chắc nhất."*',NULL,NULL,NULL,NULL,NULL);
